mapper.select:
SELECT log_id AS logId, user_id AS userId, user_name AS userName, operation_type AS operationType, CASE operation_type WHEN 1 THEN '新增' WHEN 2 THEN '修改' WHEN 3 THEN '删除' WHEN 4 THEN '登录' WHEN 5 THEN '登出' ELSE '未知' END AS operationTypeDesc, operation_module AS operationModule, operation_desc AS operationDesc, request_method AS requestMethod, request_url AS requestUrl, response_code AS responseCode, response_msg AS responseMsg, operation_time AS operationTime, ip_address AS ipAddress, is_success AS isSuccess, CASE is_success WHEN 0 THEN '失败' WHEN 1 THEN '成功' ELSE '未知' END AS isSuccessDesc, created_time AS createdTime FROM sys_operation_log WHERE is_del = 0
AND user_id = #{userId}
AND user_name LIKE CONCAT('%', #{userName}, '%')
AND operation_type = #{operationType}
AND operation_module = #{operationModule}
AND is_success = #{isSuccess}
AND created_time >= #{startTime}
AND created_time <= #{endTime}
ORDER BY created_time DESC
LIMIT #{pageNo}, #{pageSize}

SELECT COUNT(*)
FROM sys_operation_log
WHERE is_del = 0

    AND user_id = #{userId}


    AND user_name LIKE CONCAT('%', #{userName}, '%')


    AND operation_type = #{operationType}


    AND operation_module = #{operationModule}


    AND is_success = #{isSuccess}


    AND created_time >= #{startTime}


    AND created_time <= #{endTime}

SELECT COUNT(*) AS totalCount, SUM(CASE WHEN is_success = 1 THEN 1 ELSE 0 END) AS successCount, SUM(CASE WHEN is_success = 0 THEN 1 ELSE 0 END) AS failCount, SUM(CASE WHEN operation_type = 1 THEN 1 ELSE 0 END) AS addCount, SUM(CASE WHEN operation_type = 2 THEN 1 ELSE 0 END) AS updateCount, SUM(CASE WHEN operation_type = 3 THEN 1 ELSE 0 END) AS deleteCount, SUM(CASE WHEN operation_type = 4 THEN 1 ELSE 0 END) AS loginCount, SUM(CASE WHEN operation_type = 5 THEN 1 ELSE 0 END) AS logoutCount, AVG(operation_time) AS avgOperationTime FROM sys_operation_log WHERE is_del = 0
AND created_time >= #{startTime}
AND created_time <= #{endTime}
